/**
 * Section CSS Loader - Loads custom CSS for page sections
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import { useEffect } from 'react';
import { customStylesManager } from '@/lib/custom-styles';

interface SectionCSSLoaderProps {
  sections: { id: string }[];
  pageId?: string;
}

export function SectionCSSLoader({ sections, pageId }: SectionCSSLoaderProps) {
  useEffect(() => {
    // Load section CSS
    customStylesManager.loadPageSectionCSS(sections);
    
    // Load page CSS if pageId is provided
    if (pageId) {
      const pageCSS = customStylesManager.getPageCSS(pageId);
      if (pageCSS) {
        customStylesManager.applyPageCSS(pageId, pageCSS);
      }
    }
  }, [sections, pageId]);

  return null; // This component doesn't render anything
}